import{c as e,Q as o,j as l,m as r}from"./chunks/framework.BXc4yaFE.js";const h=JSON.parse('{"title":"AI Agent 是如何记住东西？从原理到实战详细解释","description":"","frontmatter":{"title":"AI Agent 是如何记住东西？从原理到实战详细解释","date":"2026-05-13T00:00:00.000Z","source":"https://x.com/lxfater/status/2054396603197505745","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-05-13-@lxfater-505745.md","filePath":"research/tweets/2026-05-13-@lxfater-505745.md","lastUpdated":1779894392000}'),i={name:"research/tweets/2026-05-13-@lxfater-505745.md"};function n(a,t,s,p,g,d){return o(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="ai-agent-是如何记住东西-从原理到实战详细解释" tabindex="-1">AI Agent 是如何记住东西？从原理到实战详细解释 <a class="header-anchor" href="#ai-agent-是如何记住东西-从原理到实战详细解释" aria-label="Permalink to &quot;AI Agent 是如何记住东西？从原理到实战详细解释&quot;">​</a></h1><ul><li><strong>URL</strong>: <a href="https://x.com/lxfater/status/2054396603197505745" target="_blank" rel="noreferrer">https://x.com/lxfater/status/2054396603197505745</a></li><li><strong>Author</strong>: @lxfater（铁锤人）</li><li><strong>Date</strong>: 2026-05-13</li><li><strong>Stats</strong>: 👍 294 · 🔁 88 · 🔖 496 · 👁 98,680</li></ul><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><p>最近Agent 的长期记忆十分火爆，每个人都在聊记忆系统</p><p>但你去翻那些讲解，多半是一堆名词砸过来：向量数据库、RAG、上下文窗口、压缩、情景记忆……</p><p>读完，你还是说不清它到底怎么运作的，是不是？</p><p>不怪你，大部分文章都默认你有基础。</p><p>但Agent的记忆系统是目前面试最火的方向，不搞清楚的话，工作和面试中会很吃亏。</p><p>所以这篇我换个讲法，从基础开始讲，不堆名词！尽量带大家读懂！！</p><p>我向你保证，看完下面你能自己答上这三个问题：</p><p><strong>记忆系统是什么？</strong><strong>如何理解OpenClaw的记忆系统？</strong><strong>企业级别方案是啥样？</strong></p><p>这篇文章特别长，耗时我几天写作，如果你有朋友对Agent记忆感兴趣，可以先收藏，后面转发给他。</p><h2 id="关于agent记忆系统的一些基础知识" tabindex="-1">关于Agent记忆系统的一些基础知识 <a class="header-anchor" href="#关于agent记忆系统的一些基础知识" aria-label="Permalink to &quot;关于Agent记忆系统的一些基础知识&quot;">​</a></h2><p>这一节主要讲Agent如何在单个会话保持记忆和不同会话之间保持记忆的。假如你已经理解，可以提前跳过。</p><p>首先对大模型的两次API调用之间是没有记忆的，啥意思呢？</p><p>举个例子：你在第一次调用中说你喜欢吃橘子，那么第二次调用中假如你没有把&quot;我喜欢吃橘子&quot;附加到提示词，那么大模型是对&quot;你喜欢吃橘子&quot;没有记忆的。</p><p>那么Agent是如何在对话中保持这个记忆呢？</p><p>首先，你每次问一句的时候，底层会把你之前和它的聊天历史都发送出去，大模型能看到，就能确保最近的记忆。</p><p>但是当聊天记录很多，以至于超过大模型接受聊天历史最大值时。它就会压缩聊天记录，就是把当前回话对话历史总结提炼一下，然后又塞回提示词，这样就有空间继续聊天了。</p><p><strong>上面就是模型如何在单个冗长对话中保持记忆的原理。</strong></p><p>现在你知道单个会话中如何保持记忆了，<strong>但在不同聊天对话之间，如何保持记忆呢？</strong></p><p><strong>这个时候，长期的记忆系统就登场了！！</strong></p><p>它做的事情就是在你上下文压缩的时候或者要求记忆某个东西的时候，把重要的信息存到某个存储空间。</p><p>然后在你开始新的对话的时候，适当的时机提取加入提示词中。</p><p>通过腾笼换鸟，构建出记住很多事情的假象。这和人类的工作记忆和长期记忆类似。</p><p>好了，有了这些基本的记忆知识后，我们就可以去了解什么是记忆系统了。</p><p>下面我将会给你一个理解框架，如果你看完，我保证让你对任何记忆系统方案都有个基本的理解。</p><h2 id="记忆系统" tabindex="-1">记忆系统 <a class="header-anchor" href="#记忆系统" aria-label="Permalink to &quot;记忆系统&quot;">​</a></h2><p>现在网上声称能给 Agent 长期记忆的方案，少说也有几十种，这么多，咋研究呀？</p><p>接下来我给你拆解一篇论文，来获得对Agent长期记忆的基本认知，后面再通过对比OpenClaw和其他记忆框架的区别获得更好的理解。</p><p>Google 在 2025 年 11 月发表了一篇论文，标题叫《Context Engineering, Sessions and Memory》</p><p>这篇论文中，他们效仿半个世纪前认知科学的方法，把Agent的记忆分为三类：</p><ul><li>情景记忆：昨天发生了啥、上次跟你聊了啥</li><li>语义记忆：你叫什么、喜欢什么、是哪种身份</li><li>程序性记忆：怎么完成一件事、流程是什么</li></ul><p>这三种记忆合起来，就是所谓的Agent的记忆。</p><p>但这只是故事的一部分，另一半关于如何维护和使用记忆的。</p><p>就像人一样，Agent也不能什么都记忆，所以记忆系统需要有一套可靠的方法，从对话历史中抽取出重要的信息，然后再保存。</p><p>这一步我称之为<strong>抽取</strong>。</p><p>除此之外，我们还要对记忆进行整理合并。</p><p>举个例子：三个月之前我说在大理，后来我搬到成都。假如不对这个信息进行合并的话，记忆中就存在相互矛盾条目。正确的做法是将，在我搬到成都后，记忆更新为：用户在成都。</p><p>这一步我称之为<strong>更新</strong>。</p><p>还有一步是<strong>检索</strong>，这里面就有很多方法了，关键词检索，语义检索，融合检索，用大模型来检索。</p><p>所以，你想要搞懂一个记忆系统，只要搞懂这两个方面就行：</p><ol><li>记忆有多少种分类，每种存什么的？</li><li>记忆是如何抽取，更新，检索？</li></ol><p>好了，利用这个框架，让我们来搞清：OpenClaw长期记忆是如何实现的。</p><p><strong>OpenClaw的记忆有多少种分类，每种存什么的？</strong></p><p>它的记忆分为下面三类：</p><ol><li><strong>memory.md（记忆）</strong>：属于语义记忆，存储你的身份、偏好、稳定事实。</li><li><strong>daily logs（每日日志）</strong>：属于情景记忆，记录每天发生了啥，按天组织，只会添加新的条目，不会删除。</li><li><strong>session snapshots（会话快照）</strong>：属于情景层记忆，当你用 /new 或 /reset 命令开启一个新会话，会总结旧对话中最后 15 条&quot;有意义的&quot;消息，保存成markdown文件。</li></ol><p><strong>抽取、更新、检索怎么做？</strong></p><p>抽取发生在三种情况下：</p><ol><li>对话即将被压缩的时候：这个时候会讲有价值的信息写入每日日志中。</li><li>你用 /new 或 /reset 命令开启一个新会话：会将有价值的信息保存到会话快照中。</li><li>用户要求记忆时候：自行判断存储在任意一种记忆中。</li></ol><p>检索会发生在下面两种情况：</p><ol><li>开启一个新的对话，就会将memory.md 都会被自动注入到 prompt，而且还会去读今天和昨天的每日日志，以获取最近的上下文。</li><li>当OpenClaw觉得有必要看记忆时，会先调用memory search，通过融合搜索（关键词+向量）找到记忆所在地点，再通过 memory get读取文件内容。</li></ol><p>那么更新发生什么时候呢？我个人理解发生在抽取的时候，就是决定记忆什么的时候。</p><p>现在你对记忆系统已经有一定了解了，但说句心里话，OpenClaw 的记忆系统问题不少：</p><ol><li>很费Token</li><li>Markdown 没了记忆就消失</li><li>经常遗忘东西</li></ol><p>但真正的企业级记忆系统做了很多优化保证稳定性，背后的技术值得任何一个喜欢技术的人搞懂。</p><h2 id="企业级-agent-记忆系统" tabindex="-1">企业级 Agent 记忆系统 <a class="header-anchor" href="#企业级-agent-记忆系统" aria-label="Permalink to &quot;企业级 Agent 记忆系统&quot;">​</a></h2><p>AI 时代，每一个程序员都该搞懂企业级 Agent 记忆系统背后的技术，否则只会越来越没优势了。</p><p>为了方便讲解，我挑一个叫 <strong>EverOS</strong> 的开源方案来拆解。</p><p><strong>第一问：记忆怎么分类？</strong></p><p>EverOS 在通用框架 3 类之下拆得更细：</p><p><strong>1. 语义记忆</strong>（分两层）：</p><ul><li>稳定特质：你是夜猫子、是程序员、住北京，这种长期不变的</li><li>临时状态：你今天熬了夜、这周特别忙、上周感冒了</li></ul><p><strong>2. 情景记忆</strong>（分三种）：</p><ul><li>Episode（剧情记忆）：把一段对话或任务梳理成的浓缩概要，不是按天的流水账</li><li>EventLog（事件日志）：把对话里的关键事实拆出来，每条带时间戳</li><li>Foresight（未来记）：跟时间有关的&quot;接下来&quot;——你说过要做的、它推断你之后会涉及的，带有效时间，到点能提醒</li></ul><p><strong>3. 程序性记忆</strong>（分两种）：</p><ul><li>Agent Case（任务档案）：干完一次任务，把&quot;想干什么 + 一步步怎么做的 + 一个质量分&quot;记下来</li><li>Agent Skill（蒸馏技能）：同类任务做过几次后，自动从这些档案里蒸馏出通用打法，还带个成熟度分，做得越多越靠谱</li></ul><p><strong>第二问：抽取、更新、检索怎么做？</strong></p><p><strong>抽取</strong>：EverOS 自动判断&quot;这一段讲完了没有&quot;，讲完就切下来，打包成一个记忆单元，包含：</p><ul><li>剧情：这一段聊了什么、做了什么</li><li>关键事实：值得单独拎出来记的事</li><li>未来记：你说过要做的、它推断之后会涉及的</li><li>上下文标签：什么时候、在哪、可信度多高、当时什么情绪</li></ul><p><strong>更新</strong>（语义巩固 Semantic Consolidation）：</p><ul><li>自动判断哪条是最新的</li><li>重复的、说的是同一件事的，合到一起</li><li>维护用户画像，把稳定偏好和临时状态分开存（官方叫 Profile Evolution）</li></ul><p><strong>检索</strong>（4 种方式）：</p><ul><li>关键词：精确匹配词，适合查具体的名字、ID</li><li>向量搜索：按语义找，同样的意思不同的词也能匹配</li><li>混合：关键词 + 向量一起跑，再用 rerank 模型筛一遍（官方推荐默认档）</li><li>Agentic：复杂多部分问题才上，LLM 自己判断该搜什么、怎么搜，来回多次直到找到</li></ul><p>EverOS 不是被动匹配，而是<strong>主动重建上下文</strong>：先分析想干什么 → 激活相关主题场景 → 过滤过期信息 → 迭代搜索直到信息够用。</p><p><strong>评测结果</strong>：EverOS 在长程记忆评测 LoCoMo 上拿了 <strong>93.05%</strong> 总体准确率（GPT-4.1-mini），对比方案 Zep 的 85.22% 高出近 8 个百分点。</p><h2 id="实际生产落地" tabindex="-1">实际生产落地 <a class="header-anchor" href="#实际生产落地" aria-label="Permalink to &quot;实际生产落地&quot;">​</a></h2><p>EverOS Cloud API 免费开放，三步搞定：</p><ol><li>浏览器打开 everos.evermind.ai 注册，获取 API Key</li><li><code>pip install everos</code></li><li>Python 里实例化 client</li></ol><p><strong>Skill 自进化功能</strong>：Agent 反复做同类任务，EverOS 自动把经验蒸馏成可复用的 skill，下次同类任务直接用，关键端点是 <code>/memories/agent</code>（普通 <code>/memories</code> 抽不出 skill）。</p><p><strong>20 个真实 Use Case</strong>（部分）：</p><ul><li>MemoCare（阿尔茨海默记忆助手）</li><li>Claude Code Plugin：给 Claude Code 装上长期记忆，跨 session 不忘</li><li>Game of Thrones：给 AI 灌权游剧情演角色</li><li>Computer-Use with Memory：让 Agent 操控电脑，记住每次操作经验</li><li>Memory Graph Visualization：把记忆系统画成可视化图谱</li></ul><p><strong>官方插件</strong>：</p><ul><li>Claude Code Plugin：每次回完话自动存、每次提问自动召回相关上下文，带 Memory Hub 面板</li><li>OpenClaw Plugin：接成 OpenClaw 的&quot;记忆槽位&quot;，跑前自动检索注入，跑完连同工具调用存回去</li></ul><p>项目信息：Apache 2.0 开源，4500+ stars，github.com/EverMind-AI/EverOS</p><hr><h2 id="分析" tabindex="-1">分析 <a class="header-anchor" href="#分析" aria-label="Permalink to &quot;分析&quot;">​</a></h2><h3 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h3><p>系統拆解 AI Agent 記憶系統三層框架（情景/語義/程序性記憶）及抽取/更新/檢索機制，以 Claude Code 原生記憶與 EverOS 企業級方案為對比案例。</p><h3 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h3><ol><li><strong>記憶系統分析框架</strong>：理解任何記憶方案只需搞懂「記憶分幾類，各存什麼」和「如何抽取、更新、檢索」兩個問題</li><li><strong>Claude Code 原生記憶的局限</strong>：memory.md + daily logs + session snapshots 三層設計費 Token、易遺忘、資料不持久</li><li><strong>EverOS 六分類精細化</strong>：在三類基礎上細分為 6 種（穩定特質 / 臨時狀態 / Episode / EventLog / Foresight / Agent Case / Agent Skill），其中 Foresight（未來記）和 Agent Skill（蒸餾技能）是顯著創新</li><li><strong>主動重建 vs 被動匹配</strong>：EverOS 檢索不是查詢-匹配，而是分析意圖 → 激活場景 → 過濾過期 → 迭代搜索的主動重建上下文</li><li><strong>LoCoMo 評測 93.05%</strong>：具體 benchmark 數字支撐方案有效性，對比 Zep 85.22% 有量化優勢</li></ol><h3 id="關鍵數據-工具-引用" tabindex="-1">關鍵數據 / 工具 / 引用 <a class="header-anchor" href="#關鍵數據-工具-引用" aria-label="Permalink to &quot;關鍵數據 / 工具 / 引用&quot;">​</a></h3><ul><li>Google 論文：《Context Engineering, Sessions and Memory》（2025 年 11 月）</li><li>EverOS LoCoMo 評測：93.05%（GPT-4.1-mini），Zep 85.22%</li><li>EverOS：github.com/EverMind-AI/EverOS，Apache 2.0，4500+ stars</li><li>EverOS 母公司：EverMind（盛大旗下 AI Native 公司）</li><li>端點關鍵差異：<code>/memories/agent</code>（Skill 蒸餾）vs <code>/memories</code>（普通記憶）</li></ul><h3 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h3><ol><li><strong>「OpenClaw」命名混淆</strong>：全文以 &quot;OpenClaw&quot; 指稱 Claude Code，技術細節（memory.md、/new 指令、session snapshots）是 Claude Code 的設計，不是虛構產品，文章命名選擇令讀者困惑</li><li><strong>EverOS 推廣色彩明顯</strong>：文末廣告式介紹（免費 API、插件、star 請求、月底新產品預告），降低純技術文章的客觀性；LoCoMo 93.05% 未說明評測條件細節（評測集規模、對比方案版本）</li><li><strong>程序性記憶的 Skill 自進化缺乏落地細節</strong>：「第一次喂軌跡只生成 case，跑過幾次才蒸餾出 skill」觸發閾值未說明，工程上如何決定「同類任務」也缺乏具體說明</li></ol><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>理由</th></tr></thead><tbody><tr><td>A. Workspace 可行動性</td><td>7/10</td><td>三層記憶分類框架可直接用來評估現有 Claude Code Memory.md 設計的盲點；EverOS API 有 Claude Code Plugin 可安裝；但文章是科普向，直接套用的 prompt / 配置指引不足</td></tr><tr><td>B. 創新性</td><td>7/10</td><td>Foresight（未來記）+ Agent Skill 蒸餾兩個子類別是現有 Claude Code workspace 規則未涵蓋的思路；但三層基礎框架來自 Google 論文，本文為二手整理</td></tr><tr><td>C. 證據品質</td><td>6/10</td><td>LoCoMo 93.05% 是具體數字，但缺乏評測細節；EverOS 插件「記憶自動存取」效果未有實驗對比；Google 論文引用正確但未附連結</td></tr><tr><td>D. 技術深度</td><td>6/10</td><td>抽取 / 更新 / 檢索機制說明清晰，Semantic Consolidation 原理有解釋；但缺乏代碼示例（文章提到有 API 但未展示），Skill 蒸餾閾值未說明</td></tr><tr><td>E. 泛化性</td><td>8/10</td><td>分析框架（兩問題法）適用任何 Agent 記憶系統評估，不限於 EverOS；三類記憶分類為通用認知框架</td></tr></tbody></table><p><strong>加權總分</strong> = 7×0.3 + 7×0.2 + 6×0.2 + 6×0.15 + 8×0.15 = <strong>6.80 / 10</strong></p><p><strong>整合決策</strong>：Skip（總分 ≤ 6 閾值為 6，本文 6.80 &gt; 6，屬於 Skip 邊界）</p><blockquote><p>重新評估：6.80 &gt; 6.0，按規則應進入整合決策樹。核心是「通用原則 / 規則」（兩問題分析框架）→ <strong>Rule</strong>（更新 <code>.claude/rules/</code> 或作為 Agent 記憶設計參考）</p></blockquote><p><strong>整合決策</strong>：Rule（補充「Agent 記憶系統評估框架」到 agentic-architecture-patterns 或 memory 設計參考）</p>',103)])])}const c=e(i,[["render",n]]);export{h as __pageData,c as default};
